key = bytes_to_long(b'ctfshow'*11)

def Solve_e(n,p):
    sum = 0
    while n > 0:
        n //= p
        sum += n
    return sum

def Solve(n):
    is_prime = [True] * (n + 1)
    primes = []
    p = 2

    while p * p <= n:
        if is_prime[p]:
            for i in range(p * 2, n + 1, p):
                is_prime[i] = False
        p += 1
    
    for i in range(2,n+1):
        if is_prime[i]:
            primes.append(i)

    sum = 1

    for p in primes:
        e = Solve_e(n,p)
        sum *= (2 * e + 1 ) % key
    return sum % key
    
d = Solve(1111111) + leak
m = pow(c,d,n)
print(long_to_bytes(m))

